import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"Alias Legal: herramientas de cumplimiento open source | Dotfiles (ES)","titleTemplate":":title","description":"Alias shell para escaneo de licencias, encabezados de copyright y gestión de atribuciones. Compatible con macOS, Linux y WSL a través de Dotfiles.","frontmatter":{"title":"Alias Legal: herramientas de cumplimiento open source","description":"Alias shell para escaneo de licencias, encabezados de copyright y gestión de atribuciones. Compatible con macOS, Linux y WSL a través de Dotfiles.","lang":"es-ES","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Legal: herramientas de cumplimiento open source preview","canonical":"/es/aliases/legal/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Legal: herramientas de cumplimiento open source","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Legal | Dotfiles","permalink":"/es/aliases/legal/","sidebar":true,"meta":[{"name":"keywords","content":"alias legal, escaneo de licencias, encabezados copyright, cumplimiento open source, dotfiles"}]},"headers":[],"relativePath":"es/aliases/legal/index.md","filePath":"es/aliases/legal/index.md","lastUpdated":1773010926000}'),r={name:"es/aliases/legal/index.md"};function s(d,e,n,c,l,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="alias-legal" tabindex="-1">Alias Legal <a class="header-anchor" href="#alias-legal" aria-label="Permalink to &quot;Alias Legal&quot;">​</a></h1><p>Herramientas de shell para cumplimiento open source, escaneo de licencias y atribuciones.</p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Los alias legal proporcionan un flujo de trabajo simplificado para cumplir con open source. Estas herramientas manejan el escaneo de licencias, encabezados de copyright y atribución de dependencias.</p><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><h3 id="escaneo-de-licencias" tabindex="-1">Escaneo de licencias <a class="header-anchor" href="#escaneo-de-licencias" aria-label="Permalink to &quot;Escaneo de licencias&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th><th>Tipo</th></tr></thead><tbody><tr><td><code>fossology-start</code></td><td>Iniciar servidor FOSSology local en el puerto 8081</td><td>Docker</td></tr><tr><td><code>fossology-stop</code></td><td>Detener servidor FOSSology</td><td>Docker</td></tr><tr><td><code>license-scan</code></td><td>Escaneo rápido de licencias del directorio actual vía Trivy</td><td>Binario</td></tr></tbody></table><h3 id="encabezados-de-copyright" tabindex="-1">Encabezados de copyright <a class="header-anchor" href="#encabezados-de-copyright" aria-label="Permalink to &quot;Encabezados de copyright&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th><th>Tipo</th></tr></thead><tbody><tr><td><code>add-headers</code></td><td>Añadir encabezados MIT de forma recursiva a archivos fuente</td><td>Docker (google/addlicense)</td></tr></tbody></table><h3 id="atribucion" tabindex="-1">Atribución <a class="header-anchor" href="#atribucion" aria-label="Permalink to &quot;Atribución&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th><th>Tipo</th></tr></thead><tbody><tr><td><code>gen-notice</code></td><td>Generar un archivo NOTICE para dependencias (Go inicialmente)</td><td>Docker</td></tr></tbody></table><h3 id="contribucion" tabindex="-1">Contribución <a class="header-anchor" href="#contribucion" aria-label="Permalink to &quot;Contribución&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th><th>Tipo</th></tr></thead><tbody><tr><td><code>check-cla</code></td><td>Vigilar checks de PR en GitHub incluyendo estado CLA</td><td>CLI (gh)</td></tr></tbody></table><h2 id="requisitos" tabindex="-1">Requisitos <a class="header-anchor" href="#requisitos" aria-label="Permalink to &quot;Requisitos&quot;">​</a></h2><ul><li><strong>Docker</strong> - Requerido para aislar herramientas de cumplimiento</li><li><strong>GitHub CLI (gh)</strong> - Requerido para PR y verificación CLA</li><li><strong>Trivy</strong> - Instalado automáticamente o sugerido para escaneo rápido</li></ul>',15)])])}const b=a(r,[["render",s]]);export{p as __pageData,b as default};
